import{_ as s,W as n,X as i,a0 as t,Y as a}from"./framework-174e6972.js";const l={},e=t(`<h2 id="_1-等价类划分法" tabindex="-1"><a class="header-anchor" href="#_1-等价类划分法" aria-hidden="true">#</a> 1. 等价类划分法</h2><h3 id="_1-1-为什么要学习等价类" tabindex="-1"><a class="header-anchor" href="#_1-1-为什么要学习等价类" aria-hidden="true">#</a> 1.1. 为什么要学习等价类？</h3><p>案例：计算两个1到100之间整数的和</p><p>分析：如果按照穷举测试，有效的测试用例都至少需要100个，需要消耗大量的时间去进行测试，也是非常无聊繁琐的工作。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636953.png" alt="image-20230601112514088" loading="lazy"></p><h3 id="_1-2-等价类的概念" tabindex="-1"><a class="header-anchor" href="#_1-2-等价类的概念" aria-hidden="true">#</a> 1.2. 等价类的概念</h3><p>在所有测试数据中，具有某种共同特征的数据子集。</p><p>等价类划分为：</p><ul><li>有效等价类：满足需求的数据子集</li><li>无效等价类：不满足需求的数据子集</li></ul><h3 id="_1-3-等价类划分法设计用例步骤" tabindex="-1"><a class="header-anchor" href="#_1-3-等价类划分法设计用例步骤" aria-hidden="true">#</a> 1.3. 等价类划分法设计用例步骤</h3><ol><li>明确需求</li><li>确定有效和无效等价类</li><li>提取数据编写测试用例</li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>无效等价类的设计规则：需求、长度、类型（字母、特殊符号、汉字、小数）、空输入</p></div><h3 id="_1-4-典型应用场景" tabindex="-1"><a class="header-anchor" href="#_1-4-典型应用场景" aria-hidden="true">#</a> 1.4. 典型应用场景</h3><p>具有典型输入框的场景，如登录注册页面，各种表单。</p><h3 id="_1-5-案例1-验证qq账号的合法性" tabindex="-1"><a class="header-anchor" href="#_1-5-案例1-验证qq账号的合法性" aria-hidden="true">#</a> 1.5. 案例1：验证QQ账号的合法性</h3><p>要求：6~10位自然数</p><p>我们按照上面的设计用例步骤，可做出如下数据：</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636954.png" alt="CleanShot 2023-06-02 at 11.16.10@2x" loading="lazy"></p><h2 id="_2-边界值分析法" tabindex="-1"><a class="header-anchor" href="#_2-边界值分析法" aria-hidden="true">#</a> 2. 边界值分析法</h2><h3 id="_2-1-为什么要学习边界值分析法" tabindex="-1"><a class="header-anchor" href="#_2-1-为什么要学习边界值分析法" aria-hidden="true">#</a> 2.1. 为什么要学习边界值分析法？</h3><p>案例：测试两个两位数整数之间的和（即-99到99之间数据求和）？</p><p>分析：通过经验发现，程序员在写代码的时候，非常容易混淆<code>&gt;=，&gt;，&lt;，&lt;=</code>运算符号，造成在边界的时候非常容易出错。</p><div class="language-php line-numbers-mode" data-ext="php"><pre class="language-php"><code><span class="token comment">//判断输入的数据是否小于-99或者大于99，如果小于-99或大于99给出错误提示 </span>
<span class="token keyword">If</span> <span class="token function">Val</span><span class="token punctuation">(</span>Text1<span class="token operator">.</span>Text<span class="token punctuation">)</span> <span class="token operator">&gt;=</span> <span class="token number">99</span> <span class="token keyword">or</span> <span class="token function">Val</span><span class="token punctuation">(</span>Text1<span class="token operator">.</span>Text<span class="token punctuation">)</span> <span class="token operator">&lt;=</span><span class="token operator">-</span> <span class="token number">99</span> Then
   <span class="token function">MsgBox</span> <span class="token punctuation">(</span><span class="token string double-quoted-string">&quot;输入的参数值必须大于-99同时小于99&quot;</span><span class="token punctuation">)</span> 
<span class="token keyword">Else</span> <span class="token keyword">if</span>
       <span class="token function">Val</span><span class="token punctuation">(</span>Text2<span class="token operator">.</span>Text<span class="token punctuation">)</span> <span class="token operator">&gt;=</span> <span class="token number">99</span> <span class="token keyword">or</span> <span class="token function">Val</span><span class="token punctuation">(</span>Text2<span class="token operator">.</span>Text<span class="token punctuation">)</span> <span class="token operator">&lt;=</span> <span class="token operator">-</span><span class="token number">99</span> Then 
       <span class="token function">MsgBox</span> <span class="token punctuation">(</span><span class="token string double-quoted-string">&quot;输入的参数值必须大于-99同时小于99&quot;</span><span class="token punctuation">)</span> Then
   <span class="token keyword">Else</span>
       Text3<span class="token operator">.</span>Text <span class="token operator">=</span> <span class="token function">Val</span><span class="token punctuation">(</span>Text1<span class="token operator">.</span>Text<span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token punctuation">(</span>Text2<span class="token operator">.</span>Text<span class="token punctuation">)</span> 
   End <span class="token keyword">if</span>
End <span class="token keyword">if</span>  
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">注意</p><p>输入的数据包含99或者-99时，边界条件设置出错：代码中将“&gt;”写成了“&gt;=”，将“&lt;”写成了“&lt;=”，造成输入99和-99时也会出错，这就不符合-99到99之间数据求和的要求了，但我们只使用等价类划分法的话，是很有可能测不到该种错误情况的，所以需要使用边界值分析法。</p></div><h3 id="_2-2-边界范围的确定" tabindex="-1"><a class="header-anchor" href="#_2-2-边界范围的确定" aria-hidden="true">#</a> 2.2. 边界范围的确定</h3><ol><li>上点：边界上的点（正好等于）（1，99）</li><li>离点：距离上点最近的点（刚好大于、刚好小于）（0，2，98，100）</li><li>内点：范围内的点（区间范围内的数据）（20，50，60）</li></ol><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636955.png" alt="image-20230601161226977" loading="lazy"></p><h3 id="_2-3-7个点优化为5个点" tabindex="-1"><a class="header-anchor" href="#_2-3-7个点优化为5个点" aria-hidden="true">#</a> 2.3. 7个点优化为5个点</h3><p>上面的7个点对我们设计测试用例来说，还是比较多，我们通过-99到99之前数据的和来分析下，减少重复的点。</p><p>上点：-99，99</p><p>内点：50</p><p>离点：-98，-100，98，100</p><h4 id="_2-3-1-99-99" tabindex="-1"><a class="header-anchor" href="#_2-3-1-99-99" aria-hidden="true">#</a> 2.3.1. [-99,99]</h4><p>取值包含-99和99时。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636956.png" alt="CleanShot 2023-06-01 at 17.08.58@2x" loading="lazy"></p><p>分析：其中的点-99，<strong>-98</strong>，50，<strong>98</strong>，99为有效点，-100，100为无效点。</p><p>按照理解来说，测上点-99，99时也测到了离点-98，98，这样理解的话就可以去掉离点-98，98，只需测五个点（-100，-99，50，99，100）。</p><h4 id="_2-3-2-99-99" tabindex="-1"><a class="header-anchor" href="#_2-3-2-99-99" aria-hidden="true">#</a> 2.3.2. (-99，99)</h4><p>取值不包含-99，99时。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636957.png" alt="CleanShot 2023-06-01 at 17.16.19@2x" loading="lazy"></p><p>分析：其中的点-98，50，98为有效点，<strong>-100</strong>，-99，99，<strong>100</strong>为无效点。</p><p>按照理解来说，测上点-99，99时也测到了离点-100，100，这样理解的话就可以去掉离点-100，100，只需测五个点（-99，-98，50，98，99）。</p><h4 id="_2-3-3-99-99" tabindex="-1"><a class="header-anchor" href="#_2-3-3-99-99" aria-hidden="true">#</a> 2.3.3. (-99，99]</h4><p>取值不包含-99，包含99时。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636958.png" alt="CleanShot 2023-06-01 at 17.23.34@2x" loading="lazy"></p><p>分析：其中的点-98，50，<strong>98</strong>，99为有效点，<strong>-100</strong>，-99，100为无效点。</p><p>按照理解来说，测上点-99，99时也测到了离点-100，100，这样理解的话就可以去掉离点-100，100，只需测五个点（-99，-98，50，98，99）。</p><div class="hint-container info"><p class="hint-container-title">7个优化为5个点</p><p>上点：必选（不考虑区间开闭） 内点：必选（建议选择中间范围） 离点：开内闭外（<strong>考虑开闭区间，开区间选择内部离点，闭区间选择外部离点</strong>）</p></div><h3 id="_2-4-设计测试用例步骤" tabindex="-1"><a class="header-anchor" href="#_2-4-设计测试用例步骤" aria-hidden="true">#</a> 2.4. 设计测试用例步骤</h3><ol><li>需求分析</li><li>划分等价类</li><li>确定边界 <ul><li>上点</li><li>内点</li><li>离点</li></ul></li><li>设计测试用例</li></ol><h3 id="_2-5-典型应用场景" tabindex="-1"><a class="header-anchor" href="#_2-5-典型应用场景" aria-hidden="true">#</a> 2.5. 典型应用场景</h3><p>数据存在边界 &gt;，&gt;=，&lt;，&lt;= 大于 小于等于，6-10位QQ号等。</p><h3 id="_2-6-案例1-qq账号-6——10位自然数" tabindex="-1"><a class="header-anchor" href="#_2-6-案例1-qq账号-6——10位自然数" aria-hidden="true">#</a> 2.6. 案例1：QQ账号（6——10位自然数）</h3><ol><li><p>需求分析</p></li><li><p>划分等价类</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636959.png" alt="CleanShot 2023-06-02 at 11.23.18@2x" loading="lazy"></p></li><li><p>确定边界</p></li></ol><table><thead><tr><th>需求</th><th>数学表示</th><th>上点</th><th>内点</th><th>离点</th><th>精简5点</th></tr></thead><tbody><tr><td>6—10位自然数</td><td>[6,10]</td><td>6 10</td><td>8</td><td>5 7 9 10</td><td>5 6 8 10 11</td></tr></tbody></table><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636960.png" alt="CleanShot 2023-06-02 at 11.00.31@2x" loading="lazy"></p><ol start="4"><li><p>设计测试用例</p><p>我们可以按照确定出来的5点，设计出来5个测试用例，但是通过和之前设计的等价类划分法核对，我们可以发现，有3个测试用例（5，6，11）和之前在等价类划分中设计的是重复的，因此可以删掉，只保留2个测试用例即可。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636961.png" alt="CleanShot 2023-06-02 at 14.30.01@2x" loading="lazy"></p></li></ol><h2 id="_3-判定表" tabindex="-1"><a class="header-anchor" href="#_3-判定表" aria-hidden="true">#</a> 3. 判定表</h2><h4 id="_3-1-判定表法的引入" tabindex="-1"><a class="header-anchor" href="#_3-1-判定表法的引入" aria-hidden="true">#</a> 3.1. 判定表法的引入</h4><p>案例：验证“若用户欠费或者关机，则不允许主被叫”功能的测试</p><p>等价类边界值分析法主要关注单个输入类条件的测试，并未考虑输入条件之间的各种组合、输入条件与输出结 果之间有相互制约关系的测试</p><h4 id="_3-2-概念" tabindex="-1"><a class="header-anchor" href="#_3-2-概念" aria-hidden="true">#</a> 3.2. 概念</h4><p>存在多个输入条件、多个输出结果，输入和输入之间有组合关系，输入和输出之间有依赖或制约关系。</p><p>如上引例可以通过以下表格表示出：</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636962.png" alt="CleanShot 2023-06-02 at 15.07.45@2x" loading="lazy"></p><h4 id="_3-3-判定表组成" tabindex="-1"><a class="header-anchor" href="#_3-3-判定表组成" aria-hidden="true">#</a> 3.3. 判定表组成</h4><ol><li><p>条件桩：所有输入条件，如欠费状态、关机状态</p></li><li><p>动作桩：所有的可能的输出结果，如允许主被叫、不允许主被叫</p></li><li><p>条件项：单个条件的取值范围，一般都是有效等价类和无效等价类</p><p>表示方式：</p><ul><li>字符： <ul><li>真/有效等价类/Y</li><li>假/无效等价类/N</li></ul></li><li>数字: <ul><li>真/有效等价类/1</li><li>假/无效等价类/0</li></ul></li></ul></li><li><p>动作项：基于每一种条件的组合，得到确认的结果，如打不通等</p></li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>在测试中我们对于真假表示说明常用以下两种方式替代：</p><table><thead><tr><th>表示形式</th><th>真</th><th>假</th></tr></thead><tbody><tr><td>数字</td><td>1</td><td>0</td></tr><tr><td>符号</td><td>Y</td><td>N</td></tr></tbody></table></div><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>规则：判定表中贯穿条件项和动作项的一列就是一条规则 假设有n个条件，每个条件的取值有2个（0,1），全组合有2^n种规则</p><p>这里就是2个条件，每个条件2个取值，可得到2^n=4种组合。</p></div><h4 id="_3-4-设计测试用例的步骤" tabindex="-1"><a class="header-anchor" href="#_3-4-设计测试用例的步骤" aria-hidden="true">#</a> 3.4. 设计测试用例的步骤</h4><ol><li>明确条件桩（找到所有的输入条件）</li><li>明确动作桩（找到所有的输出结果）</li><li>对条件桩进行全组合</li><li>明确每个组合对应的动作桩（基于每一种条件的组合情况，确定本组合下的输出结果。）</li><li>设计测试用例，每行数据对应一条测试用例</li></ol><h4 id="_3-5-使用场景" tabindex="-1"><a class="header-anchor" href="#_3-5-使用场景" aria-hidden="true">#</a> 3.5. 使用场景：</h4><p>多条件组合情况</p><h4 id="_3-6-案例1-用户呼叫" tabindex="-1"><a class="header-anchor" href="#_3-6-案例1-用户呼叫" aria-hidden="true">#</a> 3.6. 案例1：用户呼叫</h4><p>若用户欠费或关机，则不允许主被叫。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636963.png" alt="image-20230602144309362" loading="lazy"></p><h4 id="_3-7-案例2-订单状态" tabindex="-1"><a class="header-anchor" href="#_3-7-案例2-订单状态" aria-hidden="true">#</a> 3.7. 案例2：订单状态</h4><ul><li>订单检查，如果金额大于500元，又未过期，则发出批准单和提货单；</li><li>如果金额大于500元，但过期了，则不发批准单与提货单；</li><li>如果金额小于500元，则不论是否过期都发出批准单和提货单；</li><li>在过期的情况下，不论金额大小还需要发出通知单。</li></ul><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636964.png" alt="CleanShot 2023-06-02 at 14.46.49@2x" loading="lazy"></p><h4 id="_3-8-案例3-文件修改" tabindex="-1"><a class="header-anchor" href="#_3-8-案例3-文件修改" aria-hidden="true">#</a> 3.8. 案例3：文件修改</h4><p>如果想对文件进行修改，输入的第一列字符必须是A或B，第二列字符必须是一个数字。</p><ul><li>如果第一列字符不正确，则给出信息L；</li><li>如果第二列字符不正确，则给出信息M。</li></ul><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636965.png" alt="image-20230602144351183" loading="lazy"></p><h2 id="_4-因果图-扩展" tabindex="-1"><a class="header-anchor" href="#_4-因果图-扩展" aria-hidden="true">#</a> 4. 因果图（扩展）</h2><h3 id="_4-1-概念" tabindex="-1"><a class="header-anchor" href="#_4-1-概念" aria-hidden="true">#</a> 4.1. 概念</h3><p>用图解的方法表示输入的各组合关系，写出判定表，进而设计测试用例的一种【黑盒测试】方法。</p><h3 id="_4-2-使用场景" tabindex="-1"><a class="header-anchor" href="#_4-2-使用场景" aria-hidden="true">#</a> 4.2. 使用场景</h3><p>适用于分析程序输入条件的各种组合情况，以及输入和输出之间的依赖关系。</p><h3 id="_4-3-核心要素" tabindex="-1"><a class="header-anchor" href="#_4-3-核心要素" aria-hidden="true">#</a> 4.3. 核心要素</h3><ul><li>因：条件</li><li>果：结果</li></ul><h3 id="_4-4-基本符号-掌握" tabindex="-1"><a class="header-anchor" href="#_4-4-基本符号-掌握" aria-hidden="true">#</a> 4.4. 基本符号（掌握）</h3><ol><li>恒等（-）：条件成立，结果成立。</li><li>非（~）NOT：条件成立，结果不成立；条件不成立，结果成立。</li><li>或（V）OR：只要有一个条件成立，结果就成立；所有条件都不成立时，结果才不成立。</li><li>与/且（^）AND：多个条件必须同时成立，结果成立；只要有一个不成立，结果就不成立。</li></ol><h3 id="_4-5-设计测试用例的步骤" tabindex="-1"><a class="header-anchor" href="#_4-5-设计测试用例的步骤" aria-hidden="true">#</a> 4.5. 设计测试用例的步骤</h3><ol><li>需求分析</li><li>画出因果图</li><li><strong>将因果图转换为判定表</strong></li><li>生成测试用例</li></ol><blockquote><p>该方法使用很少，画因果图很麻烦，还不如直接写判定表，了解一下就行。</p></blockquote><h3 id="_4-6-案例1-文件修改" tabindex="-1"><a class="header-anchor" href="#_4-6-案例1-文件修改" aria-hidden="true">#</a> 4.6. 案例1：文件修改</h3><p>如果想对文件进行修改，输入的第一列字符必须是A或B，第二列字符必须是一个数字。</p><ul><li>如果第一列字符不正确，则给出信息L；</li><li>如果第二列字符不正确，则给出信息M。</li></ul><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636966.png" alt="因果图" loading="lazy"></p><h2 id="_5-正交法-扩展" tabindex="-1"><a class="header-anchor" href="#_5-正交法-扩展" aria-hidden="true">#</a> 5. 正交法（扩展）</h2><h3 id="_5-1-核心思想" tabindex="-1"><a class="header-anchor" href="#_5-1-核心思想" aria-hidden="true">#</a> 5.1. 核心思想</h3><p>用最小的测试用例获得最大的测试覆盖率。</p><h3 id="_5-2-正交表" tabindex="-1"><a class="header-anchor" href="#_5-2-正交表" aria-hidden="true">#</a> 5.2. 正交表</h3><p>一种特制的表，一般的正交表标记为</p>`,104),d=a("p",{class:"katex-block"},[a("span",{class:"katex-display"},[a("span",{class:"katex"},[a("span",{class:"katex-mathml"},[a("math",{xmlns:"http://www.w3.org/1998/Math/MathML",display:"block"},[a("semantics",null,[a("mrow",null,[a("msub",null,[a("mi",null,"L"),a("mi",null,"n")]),a("mo",{stretchy:"false"},"("),a("msup",null,[a("mi",null,"m"),a("mi",null,"k")]),a("mo",{stretchy:"false"},")")]),a("annotation",{encoding:"application/x-tex"}," L_n(m^k) ")])])]),a("span",{class:"katex-html","aria-hidden":"true"},[a("span",{class:"base"},[a("span",{class:"strut",style:{height:"1.1491em","vertical-align":"-0.25em"}}),a("span",{class:"mord"},[a("span",{class:"mord mathnormal"},"L"),a("span",{class:"msupsub"},[a("span",{class:"vlist-t vlist-t2"},[a("span",{class:"vlist-r"},[a("span",{class:"vlist",style:{height:"0.1514em"}},[a("span",{style:{top:"-2.55em","margin-left":"0em","margin-right":"0.05em"}},[a("span",{class:"pstrut",style:{height:"2.7em"}}),a("span",{class:"sizing reset-size6 size3 mtight"},[a("span",{class:"mord mathnormal mtight"},"n")])])]),a("span",{class:"vlist-s"},"​")]),a("span",{class:"vlist-r"},[a("span",{class:"vlist",style:{height:"0.15em"}},[a("span")])])])])]),a("span",{class:"mopen"},"("),a("span",{class:"mord"},[a("span",{class:"mord mathnormal"},"m"),a("span",{class:"msupsub"},[a("span",{class:"vlist-t"},[a("span",{class:"vlist-r"},[a("span",{class:"vlist",style:{height:"0.8991em"}},[a("span",{style:{top:"-3.113em","margin-right":"0.05em"}},[a("span",{class:"pstrut",style:{height:"2.7em"}}),a("span",{class:"sizing reset-size6 size3 mtight"},[a("span",{class:"mord mathnormal mtight",style:{"margin-right":"0.03148em"}},"k")])])])])])])]),a("span",{class:"mclose"},")")])])])])],-1),p=t('<p><strong>说明</strong></p><ul><li><p>k代表因素（输入参数）</p></li><li><p>m叫水平（输入参数的取值）</p></li><li><p>n代表测试用例数</p></li><li><p>读法：k因素m水平</p></li></ul><h3 id="_5-3-基于正交表设计测试用例的步骤" tabindex="-1"><a class="header-anchor" href="#_5-3-基于正交表设计测试用例的步骤" aria-hidden="true">#</a> 5.3. 基于正交表设计测试用例的步骤</h3><ol><li>需求分析</li><li>确定因素与水平（因素：控件名称；水平：每个控件对应的取值）</li><li>确定要采用的正交表</li><li>将正交表中的字母用文字代替</li><li>设计测试用例（一行就是一条测试用例）</li></ol><h4 id="_5-3-1-案例1-字符属性设置程序" tabindex="-1"><a class="header-anchor" href="#_5-3-1-案例1-字符属性设置程序" aria-hidden="true">#</a> 5.3.1. 案例1：字符属性设置程序</h4><p>窗体中有多个控件（字体、字符样式、颜色、字号），每个控件有多个取值</p><ul><li>字体：仿宋、楷体、华文彩云</li><li>字符样式：粗体、斜体、下划线</li><li>颜色：红色、绿色、蓝色</li><li>字号：20号、30号、40号</li></ul><h5 id="_5-3-1-1-测试用例设计步骤" tabindex="-1"><a class="header-anchor" href="#_5-3-1-1-测试用例设计步骤" aria-hidden="true">#</a> 5.3.1.1. 测试用例设计步骤</h5><ol><li><p>需求分析</p><p>窗体中有多个控件（字体、字符样式、颜色、字号），每个控件有多个取值</p></li><li><p>确定因素与水平</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636967.png" alt="CleanShot 2023-06-02 at 17.36.55@2x" loading="lazy"></p></li><li><p>确定要采用的正交表</p><p>找到我们常用的正交表中的4因素3水平。</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636968.png" alt="CleanShot 2023-06-02 at 16.29.58@2x" style="zoom:50%;"></li><li><p>将正交表中的字母用文字代替</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636969.png" alt="CleanShot 2023-06-02 at 17.07.32@2x" style="zoom:67%;"></li><li><p>设计测试用例</p><p>设计测试用例，就是每一行实验号为一个测试用例，这里略过。</p></li></ol><h3 id="_5-4-基于allpairs设计测试用例的步骤" tabindex="-1"><a class="header-anchor" href="#_5-4-基于allpairs设计测试用例的步骤" aria-hidden="true">#</a> 5.4. 基于allpairs设计测试用例的步骤</h3><ol><li>需求分析</li><li>确定因素与水平（因素：控件名称；水平：每个控件对应的取值）</li></ol><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636970.png" alt="CleanShot 2023-06-02 at 17.36.55@2x" loading="lazy"></p><ol start="3"><li>将确定的因素与水平复制到txt文件中</li></ol><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636971.png" alt="CleanShot 2023-06-02 at 17.27.39@2x" loading="lazy"></p><ol start="4"><li>打开DOS窗口，进入allpairs目录，运行命令：<code>allpairs.exe test.txt &gt; result.txt</code></li><li>根据生成的新文件编写测试用例（一行就是一条测试用例）</li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>该方法暂确认只能在win下使用，mac下暂无。</p></div><h4 id="_5-4-1-案例2-用户筛选按钮" tabindex="-1"><a class="header-anchor" href="#_5-4-1-案例2-用户筛选按钮" aria-hidden="true">#</a> 5.4.1. 案例2：用户筛选按钮</h4><p>假设有一个用户筛选功能，有3个输入分别是体型、年龄段、性别，</p><ul><li>体型有3个取值：胖、适中、瘦；</li><li>年龄段有3个取值：老人、青年、儿童；</li><li>性别有2个取值：男，女；</li></ul><p>基于allpairs设计测试用例如下：</p><table><thead><tr><th>TEST CASES</th><th></th><th></th><th></th></tr></thead><tbody><tr><td>case</td><td>体型</td><td>年龄段</td><td>性别</td></tr><tr><td>1</td><td>胖</td><td>老人</td><td>男</td></tr><tr><td>2</td><td>胖</td><td>青年</td><td>女</td></tr><tr><td>3</td><td>适中</td><td>老人</td><td>女</td></tr><tr><td>4</td><td>适中</td><td>青年</td><td>男</td></tr><tr><td>5</td><td>瘦</td><td>儿童</td><td>男</td></tr><tr><td>6</td><td>瘦</td><td>老人</td><td>女</td></tr><tr><td>7</td><td>胖</td><td>儿童</td><td>女</td></tr><tr><td>8</td><td>适中</td><td>儿童</td><td>~男</td></tr><tr><td>9</td><td>瘦</td><td>青年</td><td>~男</td></tr></tbody></table><blockquote><p>因为性别只有两个取值，导致8和9用例取得值为<code>~男</code>，这个我们不管，这里直接用男就行，用女也行，都一样。</p></blockquote><h2 id="_6-场景法-流程图法" tabindex="-1"><a class="header-anchor" href="#_6-场景法-流程图法" aria-hidden="true">#</a> 6. 场景法（流程图法）</h2><h3 id="_6-1-概念" tabindex="-1"><a class="header-anchor" href="#_6-1-概念" aria-hidden="true">#</a> 6.1. 概念</h3><p>场景法就是模拟用户操作软件时的场景，主要用于测试多个功能之间的组合使用情况。</p><h3 id="_6-2-使用测试阶段" tabindex="-1"><a class="header-anchor" href="#_6-2-使用测试阶段" aria-hidden="true">#</a> 6.2. 使用测试阶段</h3><ul><li>集成测试</li><li>系统测试</li><li>验收测试</li></ul><blockquote><p>单元测试还没到使用阶段，主要是开发人员自己对代码的功能进行测试，或者测试人员对单个功能测试，不涉及功能组合的情况。</p></blockquote><h3 id="_6-3-设计测试用例的步骤" tabindex="-1"><a class="header-anchor" href="#_6-3-设计测试用例的步骤" aria-hidden="true">#</a> 6.3. 设计测试用例的步骤</h3><ul><li><p>需求分析</p></li><li><p>绘制流程图</p></li><li><p>设计测试用例</p></li></ul><blockquote><p>每一条能走的流程路径就是一条测试用例</p></blockquote><h3 id="_6-4-流程图常用符号" tabindex="-1"><a class="header-anchor" href="#_6-4-流程图常用符号" aria-hidden="true">#</a> 6.4. 流程图常用符号</h3><ul><li><p>开始或结束：椭圆</p></li><li><p>方向或路径：箭头</p></li><li><p>处理或操作：长方形</p></li><li><p>判断：菱形</p></li><li><p>输入或输出：平行四边形</p></li></ul><h3 id="_6-5-绘制流程图" tabindex="-1"><a class="header-anchor" href="#_6-5-绘制流程图" aria-hidden="true">#</a> 6.5. 绘制流程图</h3><ol><li>确认场景中关键业务步骤</li><li>确定业务之间的先后顺序</li><li>用箭头连接即可</li></ol><h3 id="_6-6-绘制工具" tabindex="-1"><a class="header-anchor" href="#_6-6-绘制工具" aria-hidden="true">#</a> 6.6. 绘制工具</h3><ul><li><p>Microsoft Visio</p></li><li><p>各种流程图软件</p></li></ul><h4 id="_6-6-1-案例1-缺陷跟踪管理流程" tabindex="-1"><a class="header-anchor" href="#_6-6-1-案例1-缺陷跟踪管理流程" aria-hidden="true">#</a> 6.6.1. 案例1：缺陷跟踪管理流程</h4><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636972.png" alt="缺陷跟踪管理流程" loading="lazy"></p><p>案例2：ATM机取款流程</p><p>取款流程</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636973.png" alt="ATM取款流程" loading="lazy"></p><p>流程图</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/SoftwareTest/02/202306151636974.png" alt="ATM取款流程图" loading="lazy"></p><h2 id="_7-错误推测法" tabindex="-1"><a class="header-anchor" href="#_7-错误推测法" aria-hidden="true">#</a> 7. 错误推测法</h2><ul><li><p>概念：利用<strong>经验</strong>或<strong>智慧</strong>发现程序中<strong>可能</strong>犯错的地方。</p></li><li><p>使用场景</p><ul><li><p>重要功能</p></li><li><p>使用同类型产品</p></li><li><p>任务急、时间紧、资源少</p></li></ul></li></ul><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>比如一个测试很熟悉医疗软件或者测试经验十分丰富的话，那么他就可以根据自己的经验</p></div><div class="hint-container tip"><p class="hint-container-title">提示</p><p>还有一些其他的测试方法（如：状态迁移法）我们在后续进行学习。</p></div><h2 id="_8-测试用例设计方法总结" tabindex="-1"><a class="header-anchor" href="#_8-测试用例设计方法总结" aria-hidden="true">#</a> 8. 测试用例设计方法总结</h2><ul><li>具有输入功能，但输入之间没有组合关系==》【等价类】</li><li>输入有边界 如长度、类型==》【边界值】</li><li>多输入、多输出、输入与输入之间存在组合关系、输入与输出之间存在依赖或制约关系==》【判定表、因果图】</li><li>用最少的测试用例获得最大测试覆盖率时 ==》【正交法】</li><li>多个功能的组合测试 ==&gt; 【场景法、流程图】</li><li>最后推荐使用【错误推测法】来进一步补充测试用例</li></ul>',50),r=[e,d,p];function h(o,c){return n(),i("div",null,r)}const g=s(l,[["render",h],["__file","2.Common_test_methods.html.vue"]]);export{g as default};
